const monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
function phtTodayUtcMidnight() {
  const parts = new Intl.DateTimeFormat('en-US', { timeZone: 'Asia/Manila', year: 'numeric', month: '2-digit', day: '2-digit' }).formatToParts(new Date());
  const pick = (type) => parts.find((part) => part.type === type).value;
  return new Date(Date.UTC(Number(pick('year')), Number(pick('month')) - 1, Number(pick('day'))));
}
function addDays(date, days) {
  const next = new Date(date.getTime());
  next.setUTCDate(next.getUTCDate() + days);
  return next;
}
function dateParts(date) {
  const year = date.getUTCFullYear();
  const month = String(date.getUTCMonth() + 1).padStart(2, '0');
  const day = String(date.getUTCDate()).padStart(2, '0');
  const monthName = monthNames[date.getUTCMonth()];
  return { year, month, day, monthName, iso: year + '-' + month + '-' + day };
}
function pdfUrlsFor(date) {
  const part = dateParts(date);
  const base = 'https://www.treasury.gov.ph/wp-content/uploads/' + part.year + '/' + part.month + '/Treasury-Bills-Auction-Results-on-' + part.day + '-' + part.monthName + '-' + part.year;
  return [base + '.pdf', base + '-.pdf'];
}
const today = phtTodayUtcMidnight();
const daysSinceMonday = (today.getUTCDay() + 6) % 7;
const latestMonday = addDays(today, -daysSinceMonday);
const candidates = [];
for (let i = 0; i < 6; i += 1) {
  const date = addDays(latestMonday, -7 * i);
  const part = dateParts(date);
  for (const pdf_url of pdfUrlsFor(date)) {
    candidates.push({ json: { auction_date: part.iso, pdf_url, candidate_rank: candidates.length + 1 } });
  }
}
return candidates;

const items = $input.all();
const success = items.find((item) => item.binary && item.binary.data && !(item.json && item.json.error));
if (!success) {
  const attempted = items.map((item) => item.json?.pdf_url || JSON.stringify(item.json || {})).join('; ');
  throw new Error('Could not download any recent BTr Treasury Bills PDF directly. Attempted: ' + attempted);
}
return [success];

function asNumber(value) {
  return Number(String(value || '').replace(/,/g, ''));
}
const source = $items('Filter PDF Success')[0].json;
const rawText = $json.text || $json.data || $json.combined_text || Object.values($json).join(' ');
const text = String(rawText || '').replace(/\s+/g, ' ').trim();
if (!text) throw new Error('BTr PDF text extraction returned no text for ' + source.pdf_url);
const sectionMatch = text.match(/91\s*days[\s\S]*?(?=182\s*days|364\s*days|THIS IS A COMPUTER GENERATED REPORT|$)/i);
const section = sectionMatch ? sectionMatch[0] : text;
let parsed = null;
const tableMatch = section.match(/Annual\s+Rate\s+Average\s+Low\s+High\s+Comp\.?\s+Stop[-\s]?Out\s+N-C\s+Awarded\s+([0-9.,]+)\s+([0-9.,]+)\s+([0-9.,]+)\s+([0-9.,]+)\s+([0-9.,]+)\s+([0-9.,]+)/i);
if (tableMatch) parsed = asNumber(tableMatch[4]);
if (!Number.isFinite(parsed)) {
  const numbers = [...section.matchAll(/\b\d{1,3}(?:,\d{3})*(?:\.\d+)?\b/g)].map((match) => asNumber(match[0]));
  const annualRateIndex = numbers.findIndex((value, index) => value > 80 && numbers[index + 1] > 80 && numbers[index + 2] > 80 && numbers[index + 3] > 0 && numbers[index + 3] < 20);
  if (annualRateIndex !== -1) parsed = numbers[annualRateIndex + 3];
}
if (!Number.isFinite(parsed)) throw new Error('Could not parse 91-day annual average rate from extracted BTr PDF text. PDF: ' + source.pdf_url + '. Sample: ' + text.slice(0, 700));
const rate = parsed > 1 ? parsed / 100 : parsed;
if (rate <= 0 || rate > 0.20) throw new Error('Parsed BTr rate looks wrong: ' + rate + ' from ' + source.pdf_url);
if (!source.auction_date) throw new Error('Missing auction_date from selected BTr PDF candidate');
return [{ json: { key: 'BTR_91D', label: '91-day T-Bill (BTr auction)', date: source.auction_date, rate: Number(rate.toFixed(6)), source_url: source.pdf_url } }];
